1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return an empty array when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (both have only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 or 3 live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
16	    expect(result).toContainEqual([1, 0]);
17	  });
18	  it("should kill the center cell of a 3x3 block (overpopulation)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]]);
20	    expect(result).not.toContainEqual([1, 1]);
21	  });
22	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
24	    expect(result).toContainEqual([1, 1]);
25	  });
26	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
27	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
28	    const sortCells = (cells: Cell[]): Cell[] =>
29	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
30	    expect(sortCells(result)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
31	  });
32	  it.todo("should keep a 2x2 block unchanged (still life)");
33	  it.todo("should handle cells with negative coordinates");
34	});
