1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const isSameCell = (a: Cell, b: Cell): boolean => a[0] === b[0] && a[1] === b[1];
10	
11	const getNeighbors = (cell: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [cell[0] + dx, cell[1] + dy]);
13	
14	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
15	  getNeighbors(cell).filter((neighbor) =>
16	    liveCells.some((live) => isSameCell(live, neighbor))
17	  ).length;
18	
19	const isAlive = (cell: Cell, liveCells: Cell[]): boolean =>
20	  liveCells.some((live) => isSameCell(live, cell));
21	
22	const uniqueCells = (cells: Cell[]): Cell[] =>
23	  cells.filter((cell, index) =>
24	    cells.findIndex((other) => isSameCell(other, cell)) === index
25	  );
26	
27	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
28	  const candidates = uniqueCells(
29	    liveCells.flatMap((cell) => [cell, ...getNeighbors(cell)])
30	  );
31	
32	  return candidates.filter((cell) => {
33	    const liveNeighbors = countLiveNeighbors(cell, liveCells);
34	    return isAlive(cell, liveCells)
35	      ? liveNeighbors === 2 || liveNeighbors === 3
36	      : liveNeighbors === 3;
37	  });
38	};
